+++ b/src/services/preferences.service.ts
@@ -0,0 +1,143 @@
+/**
+ * Preferences service — manages user notification preferences.
+ *
+ * Provides CRUD operations for user notification preferences and
+ * a method to check whether a notification should be sent based
+ * on the user's current settings.
+ *
+ * Depends on:
+ * - PreferencesRepository for persistence
+ * - UserRepository to verify users exist
+ */
+
+import type { PreferencesRepository } from '../repositories/preferences.repository.js';
+import type { UserRepository } from '../repositories/user.repository.js';
+import type {
+  UserPreferences,
+  CreateUserPreferencesInput,
+  UpdateUserPreferencesInput,
+} from '../models/user-preferences.js';
+import type { NotificationType } from '../models/notification.js';
+import { DEFAULT_EMAIL_PREFERENCES } from '../models/user-preferences.js';
+import { Logger } from '../utils/logger.js';
+
+let nextId = 1;
+
+function generatePreferencesId(): string {
+  return `pref-${String(nextId++).padStart(4, '0')}`;
+}
+
+export function resetPreferencesIdCounter(): void {
+  nextId = 1;
+}
+
+export class PreferencesService {
+  private logger = new Logger('PreferencesService');
+
+  constructor(
+    private preferencesRepo: PreferencesRepository,
+    private userRepo: UserRepository,
+  ) {}
+
+  /**
+   * Create notification preferences for a user.
+   * Merges provided settings with defaults.
+   */
+  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
+    const user = this.userRepo.findById(input.userId);
+    if (!user) {
+      throw new Error(`User not found: ${input.userId}`);
+    }
+
+    const existing = this.preferencesRepo.findByUserId(input.userId);
+    if (existing) {
+      throw new Error(`Preferences already exist for user: ${input.userId}`);
+    }
+
+    const now = new Date();
+    const preferences: UserPreferences = {
+      id: generatePreferencesId(),
+      userId: input.userId,
+      email: {
+        ...DEFAULT_EMAIL_PREFERENCES,
+        ...input.email,
+        subscribedCategories: input.email?.subscribedCategories
+          ?? [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories],
+      },
+      createdAt: now,
+      updatedAt: now,
+    };
+
+    this.preferencesRepo.save(preferences);
+    this.logger.info(`Created preferences ${preferences.id} for user ${input.userId}`);
+    return preferences;
+  }
+
+  /**
+   * Get preferences for a user. Returns undefined if none exist.
+   */
+  getPreferences(userId: string): UserPreferences | undefined {
+    return this.preferencesRepo.findByUserId(userId);
+  }
+
+  /**
+   * Update a user's notification preferences.
+   */
+  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
+    const existing = this.preferencesRepo.findByUserId(userId);
+    if (!existing) {
+      throw new Error(`Preferences not found for user: ${userId}`);
+    }
+
+    const updatedEmail = input.email
+      ? {
+          ...existing.email,
+          ...input.email,
+          subscribedCategories: input.email.subscribedCategories
+            ?? existing.email.subscribedCategories,
+        }
+      : existing.email;
+
+    const updated = this.preferencesRepo.update(existing.id, {
+      email: updatedEmail,
+      updatedAt: new Date(),
+    } as Partial<UserPreferences>);
+
+    this.logger.info(`Updated preferences for user ${userId}`);
+    return updated;
+  }
+
+  /**
+   * Delete a user's preferences.
+   */
+  deletePreferences(userId: string): boolean {
+    const existing = this.preferencesRepo.findByUserId(userId);
+    if (!existing) {
+      return false;
+    }
+    return this.preferencesRepo.delete(existing.id);
+  }
+
+  /**
+   * Check whether an email notification should be sent to a user
+   * based on their preferences.
+   *
+   * Returns true if:
+   * - The user has no preferences (default: send all)
+   * - Email is enabled AND the notification type is in their subscribed categories
+   */
+  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
+    const prefs = this.preferencesRepo.findByUserId(userId);
+
+    // No preferences means default behavior: send everything
+    if (!prefs) {
+      return true;
+    }
+
+    if (!prefs.email.enabled) {
+      return false;
+    }
+
+    return prefs.email.subscribedCategories.includes(notificationType);
+  }
+}

